### Issue description



If the game window is forcibly closed, the print statement in the `on_disconnect` function will not output. If a breakpoint is set inside the `on_disconnect` function, the program will execute normally until the breakpoint


### control.gd
```gdscript
extends Control


@onready var tcp_client:TcpClient = TcpClient.new()

func _ready() -> void:
	tcp_client.on_connect.connect(on_connect)
	tcp_client.on_disconnect.connect(on_disconnect)
	tcp_client.on_message.connect(on_message)
	if tcp_client.connect_to_host("baidu.com", 443, true, "baidu.com") != Error.OK:
		print("connect_to_host fail")

func _exit_tree() -> void:
	tcp_client.disconnect_from_host()

func _process(delta: float) -> void:
	tcp_client.poll()

func on_connect(sender:TcpClient) -> void:
	print("connect")
	sender.put_data("GET / HTTP/1.1\r\nHost: baidu.com\r\n\r\n".to_utf8_buffer())

func on_disconnect(sender:TcpClient) -> void:
	print("on_disconnect")

func on_message(sender:TcpClient, data:PackedByteArray) -> void:
	var t:TextEdit =  %TextEdit
	t.text = (t.text + data.get_string_from_utf8())
	print("on_message: %s" % data.get_string_from_utf8())

```

### TcpClient.gd

```gdscript
extends Node

class_name TcpClient

signal on_connect(sender:TcpClient)
signal on_disconnect(sender:TcpClient)
signal on_message(sender:TcpClient, data:PackedByteArray)

var tcp:StreamPeerTCP = null
var tls:StreamPeerTLS = null
var is_tls:bool = false
var status:Status = Status.STATUS_DISCONNECTED
var _hostname:String = ""

enum Status {
	STATUS_CONNECTED,
	STATUS_DISCONNECTED,
	STATUS_CONNECTING,
	STATUS_HANDSHAKEING
}

func _init() -> void:
	tcp = StreamPeerTCP.new()
	tls = StreamPeerTLS.new()

func connect_to_host(address:String, port:int,use_tls:bool=false, hostname:String="") -> Error:
	if status != Status.STATUS_DISCONNECTED:
		return Error.ERR_BUSY
	status = Status.STATUS_CONNECTING
	is_tls = use_tls
	_hostname = hostname
	var err:Error = tcp.connect_to_host(address, port)
	if err != Error.OK:
		status = Status.STATUS_DISCONNECTED
	return err

func _disconnect_from_host(is_poll:bool=true) -> void:
	if tls.get_status() != tls.STATUS_DISCONNECTED:
		tls.disconnect_from_stream()
	if tcp.get_status() != tcp.STATUS_NONE:
		tcp.disconnect_from_host()
	if is_poll:
		poll()

func disconnect_from_host() -> void:
	_disconnect_from_host(true)

func get_status() -> Status:
	return status

func put_data(data:PackedByteArray) -> Error:
	if is_tls:
		return tls.put_data(data)
	else:
		return tcp.put_data(data)

func poll() -> void:
	match status:
		Status.STATUS_CONNECTING:
			_tcp_connect_func()
		Status.STATUS_HANDSHAKEING:
			_tls_connect_func()
		Status.STATUS_CONNECTED:
			if is_tls:
				_tls_receive_func()
			else:
				_tcp_receive_func()
		Status.STATUS_DISCONNECTED:
			_disconnect_from_host(false)

func _tcp_connect_func() -> void:
	tcp.poll()
	match tcp.get_status():
		tcp.STATUS_CONNECTED:
			if is_tls:
				status = Status.STATUS_HANDSHAKEING
				if tls.connect_to_stream(tcp, _hostname) != Error.OK:
					status = Status.STATUS_DISCONNECTED
					on_disconnect.emit(self)
					return
			else:
				status = Status.STATUS_CONNECTED
				on_connect.emit(self)
			return
		tcp.STATUS_ERROR:
			status = Status.STATUS_DISCONNECTED
			on_disconnect.emit(self)
			return
		_:
			pass

func _tls_connect_func() -> void:
	tls.poll()
	match tls.get_status():
		tls.STATUS_CONNECTED:
			status = Status.STATUS_CONNECTED
			on_connect.emit(self)
			return
		tls.STATUS_HANDSHAKING:
			return
		_:
			status = Status.STATUS_DISCONNECTED
			on_disconnect.emit(self)

func _tcp_receive_func() -> void:
	while status == Status.STATUS_CONNECTED:
		if not(tcp.poll() == Error.OK and tcp.get_status() == tcp.STATUS_CONNECTED):
			status = Status.STATUS_DISCONNECTED
			on_disconnect.emit(self)
			return
		var bytes_count:int = tcp.get_available_bytes()
		if bytes_count > 0:
			var result:Array = tcp.get_data(bytes_count)
			var err:Error = result[0] as Error
			var data:PackedByteArray = result[1] as PackedByteArray
			if err == Error.OK:
				on_message.emit(self, data)
		else:
			return

func _tls_receive_func() -> void:
	while status == Status.STATUS_CONNECTED:
		tls.poll()
		if not(tls.get_status() == tls.STATUS_CONNECTED):
			status = Status.STATUS_DISCONNECTED
			on_disconnect.emit(self)
			return
		var bytes_count:int = tls.get_available_bytes()
		if bytes_count > 0:
			var result:Array = tls.get_data(bytes_count)
			var err:Error = result[0] as Error
			var data:PackedByteArray = result[1] as PackedByteArray
			if err == Error.OK:
				on_message.emit(self, data)
		else:
			return

